import argparse
import logging
from kafka import KafkaAdminClient
from kafka.admin import NewTopic

def validate_topic_name(name):
    if not name.isalnum() or len(name) > 255:
        raise ValueError("Invalid topic name. Must be alphanumeric and less than 256 characters.")
    return name

def parse_arguments():
    parser = argparse.ArgumentParser(description='Kafka Cluster Administration')
    parser.add_argument('--bootstrap-server', required=True, help='Kafka bootstrap server')
    parser.add_argument('--topic', required=True, type=validate_topic_name, help='Topic name')
    parser.add_argument('--partitions', type=int, default=1, help='Number of partitions')
    parser.add_argument('--replication-factor', type=int, default=1, help='Replication factor')
    parser.add_argument('--config', nargs='*', help='Topic configuration in key=value format')
    return parser.parse_args()

def create_topic(admin_client, topic_name, num_partitions, replication_factor, config):
    topic_configs = {}
    if config:
        for conf in config:
            key, value = conf.split('=')
            topic_configs[key] = value

    new_topic = NewTopic(name=topic_name, num_partitions=num_partitions, replication_factor=replication_factor, topic_configs=topic_configs)
    admin_client.create_topics([new_topic])

def main():
    logging.basicConfig(level=logging.INFO)
    args = parse_arguments()

    try:
        admin_client = KafkaAdminClient(bootstrap_servers=args.bootstrap_server, security_protocol='SSL')
        create_topic(admin_client, args.topic, args.partitions, args.replication_factor, args.config)
        logging.info(f"Topic '{args.topic}' created successfully.")
    except Exception as e:
        logging.error(f"Failed to create topic: {e}")
    finally:
        admin_client.close()

if __name__ == "__main__":
    main()